const COMBINED_PATH = PATH_SEGMENTS.join(' ');

const EXTRA_PHOTO_VERTICAL_PATTERN = [-180, 180, -120, 120, -220, 220];

const getExtraPhotoSize = (viewportWidth: number) => {
  if (viewportWidth <= 600) return 138;
  if (viewportWidth <= 900) return 174;
  return 222;
};

const parseSvgRoadmap = (svgText: string, expectedPhotoCount: number) => {
  const viewBoxMatch = svgText.match(/viewBox="([^"]+)"/i);
  const viewBoxValues = viewBoxMatch?.[1].trim().split(/\s+/).map(Number);
  const pathMatch = svgText.match(/<path[^>]*d="([^"]+)"/i);

  if (!viewBoxValues || viewBoxValues.length !== 4 || !pathMatch) {
    return null;
  }

  const [, , width, height] = viewBoxValues;
  const path = pathMatch[1];
  const subpaths = path.match(/M[^M]*/g) ?? [];
  const numberRegex = /-?\d*\.?\d+/g;
  const minCenterDistance = Math.max(width, height) * 0.012;

  const selectDistinctAnchors = (candidates: PhotoAnchor[], count: number) => {
    if (count <= 0) return [];

    const selected: PhotoAnchor[] = [];
    for (const candidate of candidates) {
      const hasOverlap = selected.some((picked) => {
        const dx = picked.x - candidate.x;
        const dy = picked.y - candidate.y;
        return Math.hypot(dx, dy) < minCenterDistance;
      });

      if (!hasOverlap) {
        selected.push(candidate);
      }

      if (selected.length === count) {
        break;
      }
    }

    return selected;
  };

  const circleTagCandidates = Array.from(
    svgText.matchAll(/<circle[^>]*\bcx="([^"]+)"[^>]*\bcy="([^"]+)"[^>]*\br="([^"]+)"[^>]*>/gi),
  )
    .map((match) => {
      const x = Number(match[1]);
      const y = Number(match[2]);
      const r = Number(match[3]);
      if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(r) || r <= 0) {
        return null;
      }
      return { x, y, size: r * 2 };
    })
    .filter((anchor): anchor is PhotoAnchor => anchor !== null);

  const pathCandidates = subpaths
    .map((subpath) => {
      const numbers = subpath.match(numberRegex)?.map(Number) ?? [];
      if (numbers.length < 8) return null;

      const xs = numbers.filter((_, index) => index % 2 === 0);
      const ys = numbers.filter((_, index) => index % 2 === 1);
      const minX = Math.min(...xs);
      const maxX = Math.max(...xs);
      const minY = Math.min(...ys);
      const maxY = Math.max(...ys);
      const bboxWidth = maxX - minX;
      const bboxHeight = maxY - minY;
      const size = Math.max(bboxWidth, bboxHeight);
      const aspectRatio = bboxWidth === 0 || bboxHeight === 0
        ? Number.POSITIVE_INFINITY
        : Math.max(bboxWidth, bboxHeight) / Math.min(bboxWidth, bboxHeight);

      if (size < 16 || size > 240 || aspectRatio > 2.2) {
        return null;
      }

      return {
        x: (minX + maxX) / 2,
        y: (minY + maxY) / 2,
        size,
      };
    })
    .filter((anchor): anchor is PhotoAnchor => anchor !== null);

  const expectedCircleSize = Math.max(width, height) * 0.028;
  const pathCircleLikeCandidates = subpaths
    .map((subpath) => {
      const numbers = subpath.match(numberRegex)?.map(Number) ?? [];
      if (numbers.length < 12) return null;

      const points: PointOnPath[] = [];
      for (let i = 0; i + 1 < numbers.length; i += 2) {
        points.push({ x: numbers[i], y: numbers[i + 1] });
      }
      if (points.length < 6) return null;

      const xs = points.map((p) => p.x);
      const ys = points.map((p) => p.y);
      const minX = Math.min(...xs);
      const maxX = Math.max(...xs);
      const minY = Math.min(...ys);
      const maxY = Math.max(...ys);
      const bboxWidth = maxX - minX;
      const bboxHeight = maxY - minY;
      const size = Math.max(bboxWidth, bboxHeight);
      const aspectRatio = bboxWidth === 0 || bboxHeight === 0
        ? Number.POSITIVE_INFINITY
        : Math.max(bboxWidth, bboxHeight) / Math.min(bboxWidth, bboxHeight);

      if (size < 22 || size > 86 || aspectRatio > 1.14) {
        return null;
      }

      let signedArea = 0;
      for (let i = 0; i < points.length; i++) {
        const a = points[i];
        const b = points[(i + 1) % points.length];
        signedArea += a.x * b.y - b.x * a.y;
      }
      const area = Math.abs(signedArea) / 2;
      const bboxArea = bboxWidth * bboxHeight;
      if (!bboxArea) return null;

      const areaRatio = area / bboxArea;
      if (areaRatio < 0.52 || areaRatio > 0.93) {
        return null;
      }

      return {
        x: (minX + maxX) / 2,
        y: (minY + maxY) / 2,
        size,
      };
    })
    .filter((anchor): anchor is PhotoAnchor => anchor !== null);

  const allCandidates = [...circleTagCandidates, ...pathCircleLikeCandidates, ...pathCandidates];
  const sortedByCircleLikelihood = allCandidates
    .sort((a, b) => {
      const aScore = Math.abs(a.size - expectedCircleSize);
      const bScore = Math.abs(b.size - expectedCircleSize);
      if (aScore !== bScore) return aScore - bScore;
      return a.y - b.y || a.x - b.x;
    });

  const distinctBySize = selectDistinctAnchors(
    sortedByCircleLikelihood,
    expectedPhotoCount > 0 ? expectedPhotoCount : sortedByCircleLikelihood.length,
  );

  const anchors = distinctBySize
    .sort((a, b) => (a.y - b.y) || (a.x - b.x));

  return {
    width,
    height,
    path,
    anchors: anchors.slice(0, expectedPhotoCount),
  };
};

const LifeRoadmap: React.FC<LifeRoadmapProps> = ({ milestones, theme, roadmapPhotos = [], roadmapSvgSrc }) => {
  const pathRef = useRef<SVGPathElement>(null);
  const sectionRef = useRef<HTMLDivElement>(null);
  const [milestonePoints, setMilestonePoints] = useState<PointOnPath[]>([]);
  const [roadmapPhotoAnchors, setRoadmapPhotoAnchors] = useState<PhotoAnchor[]>([]);
  const [endPoint, setEndPoint] = useState<PointOnPath | null>(null);
  const [activeMilestone, setActiveMilestone] = useState<number | null>(null);
  const [pathLength, setPathLength] = useState(0);
  const [drawProgress, setDrawProgress] = useState(0);
  const [dariyaPath, setDariyaPath] = useState<string | null>(null);
  const [customRoadmapPath, setCustomRoadmapPath] = useState<string | null>(null);
  const [customSvgSize, setCustomSvgSize] = useState<{ width: number; height: number } | null>(null);
  const [viewportMetrics, setViewportMetrics] = useState<ViewportMetrics>({
    sectionTop: 0,
    sectionHeight: 1,
    viewportHeight: 1,
    viewportWidth: 1024,
  });

  useEffect(() => {
    if (!roadmapSvgSrc) {
      setCustomRoadmapPath(null);
      setCustomSvgSize(null);
      setRoadmapPhotoAnchors([]);
      return;
    }

    let cancelled = false;

    fetch(toAssetUrl(roadmapSvgSrc))
      .then((response) => response.text())
      .then((svgText) => {
        if (cancelled) return;
        const parsed = parseSvgRoadmap(svgText, roadmapPhotos.length);
        if (!parsed) return;
        setCustomRoadmapPath(parsed.path);
        setCustomSvgSize({ width: parsed.width, height: parsed.height });
        setRoadmapPhotoAnchors(parsed.anchors);
      })
      .catch(() => {
        if (!cancelled) {
          setCustomRoadmapPath(null);
          setCustomSvgSize(null);
          setRoadmapPhotoAnchors([]);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [roadmapSvgSrc, roadmapPhotos.length]);

  useEffect(() => {
    if (theme !== 'pink') {
      setDariyaPath(null);
      return;
    }

    let cancelled = false;

    fetch(toAssetUrl('/Dariya line.svg'))
      .then((response) => response.text())
      .then((svgText) => {
        if (cancelled) return;
        const match = svgText.match(/<path[^>]*d="([^"]+)"/i);
        setDariyaPath(match ? match[1] : null);
      })
      .catch(() => {
        if (!cancelled) setDariyaPath(null);
      });

    return () => {
      cancelled = true;
    };
  }, [theme]);

  const roadmapPath = customRoadmapPath ?? (theme === 'pink' && dariyaPath ? dariyaPath : COMBINED_PATH);
  const activeSvgW = customSvgSize?.width ?? (theme === 'pink' && dariyaPath ? DARIYA_SVG_W : SVG_W);
  const activeSvgH = customSvgSize?.height ?? (theme === 'pink' && dariyaPath ? DARIYA_SVG_H : SVG_H);

  const computePoints = useCallback(() => {
    const path = pathRef.current;
    if (!path) return;

    const total = path.getTotalLength();
    setPathLength(total);

    const pts: PointOnPath[] = [];
    const n = milestones.length;
    for (let i = 0; i < n; i++) {
      const fraction = (i + 0.5) / n;
      const t = fraction * total;
      const p = path.getPointAtLength(t);
      pts.push({ x: p.x, y: p.y });
    }
    setMilestonePoints(pts);

    if (roadmapPhotoAnchors.length < roadmapPhotos.length) {
      const photoPts: PhotoAnchor[] = [];
      const photoCount = roadmapPhotos.length;
      const photoSize = getExtraPhotoSize(viewportMetrics.viewportWidth);
      const existingAnchors = roadmapPhotoAnchors.slice(0, photoCount);
      photoPts.push(...existingAnchors);

      const isFarEnoughFromExisting = (candidate: PointOnPath) => {
        return photoPts.every((anchor) => {
          const dx = anchor.x - candidate.x;
          const dy = anchor.y - candidate.y;
          return Math.hypot(dx, dy) > photoSize * 0.45;
        });
      };

      for (let i = 0; i < photoCount; i++) {
        if (photoPts.length >= photoCount) break;
        const fraction = (i + 1) / (photoCount + 1);
        const t = fraction * total;
        const p = path.getPointAtLength(t);
        if (!isFarEnoughFromExisting(p)) continue;
        photoPts.push({ x: p.x, y: p.y, size: photoSize });
      }

      if (photoPts.length < photoCount) {
        for (let i = 0; i < photoCount * 3 && photoPts.length < photoCount; i++) {
          const fraction = (i + 0.5) / (photoCount * 3);
          const t = fraction * total;
          const p = path.getPointAtLength(t);
          if (!isFarEnoughFromExisting(p)) continue;
          photoPts.push({ x: p.x, y: p.y, size: photoSize });
        }
      }
      setRoadmapPhotoAnchors(photoPts);
    }

    const ep = path.getPointAtLength(total);
    setEndPoint({ x: ep.x, y: ep.y });
  }, [milestones.length, roadmapPath, roadmapPhotos.length, roadmapPhotoAnchors.length, viewportMetrics.viewportWidth]);

  useEffect(() => {
    computePoints();
  }, [computePoints]);

  useEffect(() => {
    if (!sectionRef.current || pathLength === 0) return;

    let ticking = false;
    const handleScroll = () => {
      if (ticking) return;
      ticking = true;
      requestAnimationFrame(() => {
        const rect = sectionRef.current!.getBoundingClientRect();
        const windowH = window.innerHeight;
        const scrolledInto = windowH - rect.top;
        const progress = Math.max(0, Math.min(1, scrolledInto / (rect.height + windowH * 1.2)));
        setDrawProgress(progress);
        setViewportMetrics({
          sectionTop: rect.top,
          sectionHeight: rect.height,
          viewportHeight: windowH,
          viewportWidth: window.innerWidth,
        });
        ticking = false;
      });
    };

    handleScroll();
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, [pathLength]);

  const strokeColor = theme === 'pink' ? '#E21C4A' : '#9b2335';
  const strokeLight = theme === 'pink' ? '#f8a4c0' : '#c4586a';
  const glowColor = theme === 'pink' ? 'rgba(226, 28, 74, 0.15)' : 'rgba(155, 35, 53, 0.12)';
  const dotBg = theme === 'pink'
    ? 'linear-gradient(135deg, #fce4ec, #f8bbd0)'
    : 'linear-gradient(135deg, #f0d0dc, #d4899f)';
  const dotBorder = theme === 'pink' ? '#E21C4A' : '#6d0035';

  const dashOffset = pathLength * (1 - drawProgress);

  const getMilestoneCardSide = (point: PointOnPath): 'left' | 'right' => {
    return point.x > activeSvgW / 2 ? 'left' : 'right';
  };

  const getNearestMilestoneIndex = (point: PointOnPath) => {
    if (!milestonePoints.length) return -1;

    let nearestIndex = 0;
    let nearestDistance = Number.POSITIVE_INFINITY;

    milestonePoints.forEach((milestonePoint, index) => {
      const dx = milestonePoint.x - point.x;
      const dy = milestonePoint.y - point.y;
      const distance = (dx * dx) + (dy * dy);
      if (distance < nearestDistance) {
        nearestDistance = distance;
        nearestIndex = index;
      }
    });

    return nearestIndex;
  };

  const getEdgeFadeOpacity = (screenY: number, photoSize: number) => {
    const fadeStart = photoSize * 0.95;
    const topEdgeDistance = screenY + photoSize * 0.45;
    const bottomEdgeDistance = viewportMetrics.viewportHeight - (screenY - photoSize * 0.45);
    const minDistance = Math.min(topEdgeDistance, bottomEdgeDistance);
    return Math.max(0, Math.min(1, minDistance / fadeStart));
  };

  return (
    <div className="life-roadmap" ref={sectionRef}>
      <div className="roadmap-container">
        <svg
          viewBox={`0 0 ${activeSvgW} ${activeSvgH}`}
          className="roadmap-svg"
          preserveAspectRatio="xMidYMin meet"
        >
          {/* Glow */}
          <path
            d={roadmapPath}
            fill="none"
            stroke={glowColor}
            strokeWidth="20"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeDasharray={pathLength}
            strokeDashoffset={dashOffset}
          />

          {/* Shadow offset for depth */}
          <path
            d={roadmapPath}
            fill="none"
            stroke={strokeLight}
            strokeWidth="8"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeDasharray={pathLength}
            strokeDashoffset={dashOffset}
            opacity="0.25"
            transform="translate(2, 2)"
          />

          {/* Main thread */}
          <path
            ref={pathRef}
            d={roadmapPath}
            fill="none"
            stroke={strokeColor}
            strokeWidth="6"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeDasharray={pathLength}
            strokeDashoffset={dashOffset}
          />

          {/* Highlight */}
          <path
            d={roadmapPath}
            fill="none"
            stroke="rgba(255,255,255,0.2)"
            strokeWidth="2"
            strokeLinecap="round"
            strokeDasharray={pathLength}
            strokeDashoffset={dashOffset}
            transform="translate(-1, -1)"
          />

          {/* Milestone circles on the path */}
          {milestonePoints.map((pt, i) => {
            const fraction = (i + 0.5) / milestones.length;
            const isVisible = drawProgress >= fraction - 0.05;
            const isActive = activeMilestone === i;

            return (
              <g key={i}>
                {isActive && (
                  <circle
                    cx={pt.x} cy={pt.y} r="38"
                    fill="none" stroke={strokeColor}
                    strokeWidth="1.5" opacity="0.2"
                    className="node-pulse"
                  />
                )}
                <circle
                  cx={pt.x} cy={pt.y} r="28"
                  fill="white" stroke={strokeColor}
                  strokeWidth="3" opacity={isVisible ? 1 : 0}
                />
                <circle
                  cx={pt.x} cy={pt.y} r="22"
                  fill={strokeColor}
                  opacity={isVisible ? 0.08 : 0}
                />
              </g>
            );
          })}

          {/* Union flourish at the end of the line */}
          {theme !== 'pink' && endPoint && drawProgress > 0.92 && (
            <g
              transform={`translate(${endPoint.x - UNION_W * 0.5}, ${endPoint.y - UNION_H * 0.35})`}
              className="union-flourish"
              opacity={Math.min(1, (drawProgress - 0.92) / 0.08)}
            >
              <path d={UNION_PATH} fill={strokeColor} />
            </g>
          )}
        </svg>

        {/* Milestone cards + photo dots */}
        <div className="roadmap-cards-overlay">
          {roadmapPhotoAnchors.map((pt, i) => {
            const fraction = roadmapPhotoAnchors.length > 1
              ? i / Math.max(roadmapPhotoAnchors.length - 1, 1)
              : 0;
            const revealLead = i >= roadmapPhotoAnchors.length - 4 ? 0.2 : 0.12;
            const yPct = (pt.y / activeSvgH) * 100;
            const xPct = (pt.x / activeSvgW) * 100;
            const useCustomAnchors = Boolean(customRoadmapPath && roadmapPhotoAnchors.length);
            const nearestMilestoneIndex = getNearestMilestoneIndex(pt);
            const nearestMilestonePoint = nearestMilestoneIndex >= 0 ? milestonePoints[nearestMilestoneIndex] : pt;
            const nearestMilestoneSide = getMilestoneCardSide(nearestMilestonePoint);
            const cardOppositeDirection = nearestMilestoneSide === 'left' ? 1 : -1;
            const edgeAwareDirection = xPct < 30 ? 1 : xPct > 70 ? -1 : cardOppositeDirection;
            const offsetX = useCustomAnchors ? 0 : edgeAwareDirection * (170 + (i % 2) * 42);
            const offsetY = useCustomAnchors ? 0 : EXTRA_PHOTO_VERTICAL_PATTERN[i % EXTRA_PHOTO_VERTICAL_PATTERN.length];
            const photoSize = useCustomAnchors ? pt.size : getExtraPhotoSize(viewportMetrics.viewportWidth);
            const screenY = viewportMetrics.sectionTop + (yPct / 100) * viewportMetrics.sectionHeight + offsetY;
            const edgeFadeOpacity = getEdgeFadeOpacity(screenY, photoSize);
            const isVisible = useCustomAnchors
              ? edgeFadeOpacity > 0.02
              : drawProgress >= fraction - revealLead && edgeFadeOpacity > 0;

            return (
              <div
                key={`extra-photo-${i}`}
                className={`roadmap-extra-photo ${isVisible ? 'visible' : ''}`}
                style={{
                  top: `${yPct}%`,
                  left: `${xPct}%`,
                  '--photo-offset-x': `${offsetX}px`,
                  '--photo-offset-y': `${offsetY}px`,
                  opacity: isVisible ? edgeFadeOpacity : 0,
                } as CSSProperties}
              >
                <div
                  className="roadmap-photo-node roadmap-photo-node-extra"
                  style={{
                    background: dotBg,
                    borderColor: dotBorder,
                    width: `${photoSize}px`,
                    height: `${photoSize}px`,
                  }}
                >
                  <ImageWithFallback
                    src={roadmapPhotos[i]}
                    alt={`Roadmap photo ${i + 1}`}
                    className="roadmap-photo-img"
                    fallback={<span className="roadmap-photo-emoji">📷</span>}
                  />
                </div>
              </div>
            );
          })}

          {milestonePoints.map((pt, i) => {
            const fraction = (i + 0.5) / milestones.length;
            const isVisible = drawProgress >= fraction - 0.05;
            const side = getMilestoneCardSide(pt);
            const m = milestones[i];
            const useCustomRoadmapLayout = Boolean(customRoadmapPath);
            const sideOffsetPercent = useCustomRoadmapLayout
              ? (viewportMetrics.viewportWidth <= 700 ? 7 : 10)
              : 4;
            const verticalOffsetPx = useCustomRoadmapLayout
              ? (viewportMetrics.viewportWidth <= 700 ? 84 : 128)
              : 0;

            const yPct = (pt.y / activeSvgH) * 100;
            const xPct = (pt.x / activeSvgW) * 100;

            return (
              <div
                key={i}
                className={`roadmap-milestone ${side} ${isVisible ? 'visible' : ''} ${activeMilestone === i ? 'active' : ''}`}
                style={{
                  top: `calc(${yPct}% + ${verticalOffsetPx}px)`,
                  ...(side === 'left'
                    ? { right: `${100 - xPct + sideOffsetPercent}%` }
                    : { left: `${xPct + sideOffsetPercent}%` }),
                }}
                onMouseEnter={() => setActiveMilestone(i)}
                onMouseLeave={() => setActiveMilestone(null)}
              >
                <div className={`roadmap-card ${theme}`}>
                  <span className="roadmap-year script-font">{m.year}</span>
                  <h3 className="roadmap-card-title">{m.title}</h3>
                  <p className="roadmap-card-desc">{m.description}</p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default LifeRoadmap;
